css:
.loader {--loader-bg: #ffffff;
  --loader-secondary-color: #f0abfc;
   width: 50px;
   height: 60px;
   color: var(--loader-color, #6d28d9);
   display: grid;
}
.loader:before, .loader:after  {
  content: "";
   background: linear-gradient(90deg,currentColor calc(100% - 15px),#0000 0) 0 50%/100% 10px, conic-gradient(from -136deg at 15px 50%,#0000 ,currentColor 1deg 90deg,#0000 91deg) 35px 0/100% 100%;
   background-repeat: repeat-x;
   animation: l6 1s infinite;
}
.loader:after  {
  transform: scaleX(-1);
}
@keyframes l6  {
  80%,100%{background-position: 50px 50%,85px 0}
}
